import React, { useEffect, useState } from 'react';
import api from '../api/axiosConfig';
import marketSocket from '../api/socketConfig';
import { LayoutDashboard, History, Zap, ExternalLink } from 'lucide-react';

const DashboardPage = () => {
  const [history, setHistory] = useState([]);
  const [loading, setLoading] = useState(true);
  const [livePrices, setLivePrices] = useState({});

  useEffect(() => {
    const loadDashboard = async () => {
      try {
        const res = await api.get('/portfolio/history');
        
        // Parse holdings if they arrived as JSON strings from PostgreSQL
        const formattedData = res.data.map(item => ({
          ...item,
          holdings: typeof item.holdings === 'string' ? JSON.parse(item.holdings) : item.holdings
        }));
        
        setHistory(formattedData);
      } catch (err) {
        console.error("DASHBOARD_LOAD_ERROR:", err);
      } finally {
        setLoading(false);
      }
    };

    loadDashboard();
  }, []);

  // Market Pulse: Connect to WebSocket and listen for price updates
  useEffect(() => {
    marketSocket.connect();
    
    const unsubscribe = marketSocket.addListener((data) => {
      // Expecting data in format: { "RELIANCE.NS": 2500.45, ... }
      setLivePrices(prev => ({ ...prev, ...data }));
    });

    return () => unsubscribe();
  }, []);

  if (loading) {
    return (
      <div className="min-h-[60vh] flex items-center justify-center font-mono">
        <p className="text-emerald-500/50 text-xs animate-pulse tracking-[0.4em]">
          QUERYING_STRATEGY_VAULT...
        </p>
      </div>
    );
  }

  return (
    <div className="max-w-6xl mx-auto space-y-8 animate-in fade-in duration-700">
      {/* Header Section */}
      <div className="flex items-center justify-between border-b border-white/5 pb-6">
        <div>
          <h1 className="flex items-center gap-3 text-2xl font-bold tracking-tighter text-white">
            <LayoutDashboard className="text-emerald-500" size={24} />
            TERMINAL_DASHBOARD
          </h1>
          <p className="text-[10px] text-white/30 uppercase tracking-widest mt-1">
            Secure Node: Established // Vault_Status: Online
          </p>
        </div>
        <div className="text-right">
          <div className="text-[10px] text-emerald-500/50 uppercase font-bold">Total_Strategies</div>
          <div className="text-xl font-mono">{history.length.toString().padStart(2, '0')}</div>
        </div>
      </div>

      {/* Strategy Grid */}
      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
        {history.map((item) => (
          <div 
            key={item.id} 
            className="group bg-[#1a1a1a] border border-white/10 p-6 rounded-xl hover:border-emerald-500/30 transition-all duration-300 relative overflow-hidden"
          >
            {/* Background Glow */}
            <div className="absolute -right-4 -top-4 w-24 h-24 bg-emerald-500/5 rounded-full blur-2xl group-hover:bg-emerald-500/10 transition-colors" />

            <div className="flex justify-between items-start mb-4">
              <span className="text-[9px] bg-white/5 px-2 py-1 rounded text-white/40 font-mono">
                ID_{item.id.toString().padStart(4, '0')}
              </span>
              <span className="text-[9px] text-emerald-500/70 font-bold flex items-center gap-1">
                <History size={10} /> {new Date(item.created_at).toLocaleDateString()}
              </span>
            </div>

            <h3 className="text-white font-bold text-lg mb-2 line-clamp-1 group-hover:text-emerald-400 transition-colors">
              {item.goal}
            </h3>
            
            <p className="text-xs text-white/50 leading-relaxed mb-6 line-clamp-2 italic">
              "{item.summary}"
            </p>

            {/* Holdings & Live Pulse */}
            <div className="space-y-2 mb-6">
              <div className="text-[9px] uppercase tracking-widest text-white/20 font-bold">Live_Market_Pulse</div>
              <div className="flex flex-wrap gap-2">
                {item.holdings && Array.isArray(item.holdings) ? (
                  item.holdings.slice(0, 3).map((stock, idx) => (
                    <div key={idx} className="flex items-center gap-2 bg-black/40 px-3 py-1.5 rounded-lg border border-white/5">
                      <span className="text-[10px] font-bold text-white/80">{stock.ticker || stock}</span>
                      <span className="text-[10px] font-mono text-emerald-500">
                        {livePrices[stock.ticker || stock] ? (
                          `₹${livePrices[stock.ticker || stock]}`
                        ) : (
                          <Zap size={10} className="animate-pulse" />
                        )}
                      </span>
                    </div>
                  ))
                ) : (
                  <span className="text-[10px] text-white/20">NO_ASSETS_INDEXED</span>
                )}
              </div>
            </div>

            <button className="w-full flex items-center justify-center gap-2 py-3 bg-white/5 hover:bg-emerald-500 hover:text-black rounded-lg text-[10px] font-bold uppercase tracking-widest transition-all">
              Inspect_Full_Strategy <ExternalLink size={12} />
            </button>
          </div>
        ))}

        {history.length === 0 && (
          <div className="col-span-full py-20 border border-dashed border-white/10 rounded-2xl flex flex-col items-center justify-center text-center">
            <div className="w-12 h-12 rounded-full bg-white/5 flex items-center justify-center mb-4">
              <History className="text-white/20" />
            </div>
            <p className="text-white/40 text-sm font-mono tracking-tighter">
              VAULT_IS_EMPTY: NO_STRATEGIES_GENERATED_YET
            </p>
            <button className="mt-4 text-[10px] text-emerald-500 hover:underline uppercase tracking-widest">
              Initialize_First_Query →
            </button>
          </div>
        )}
      </div>
    </div>
  );
};

export default DashboardPage;
